import sqlite3   # Importing Python's built-in SQLite module (sqlite3).
def get_order(userid, orderid):  # Defining a function to retrieve an order from the database using user id and Order ID.
    conn = None     # Initializing connection variable as null at first.  
                    # This will be used later in our code (connecting SQLite Database)     
                    
    try:            # Try block for exception handling  - if any error occurs during the execution of this section, it'll go to catch-block and handle that specific case    
        conn = sqlite3.connect('my_database.db')   # Connecting SQLite database (Creates a connection object)    . This will open up our 'SQLite Database'.  The name my_Database is the file we are going to create, in this example it's named "ordersDB"
        cursor = conn.cursor()     # Initializing Cursor Object   - A special database-like pointer that allows us execute SQL commands on a specific DB (database).    . It points at one row of data and then moves forward with the next command  to read/write into it, etc...     
        
        cursor.execute("SELECT * FROM orders WHERE user_id=? AND order_id = ?",(userid ,orderid))   # Executes a SQL query on database using placeholders (?) and parameters (?). This will select all the rows from 'orders' table where "User id" is equal to passed parameter, 
                                                                                                           # And also for Order ID. The order_ID should be same as given in function call arguments   .    It returns a cursor object which we can iterate over using loop (fetch)    
        
        rows = cursor.fetchall()      # Fetch all the remaining data from last executed statement and store it into 'rows' variable  - This will return list of tuples, where each tuple contains one row in result set   .    It is used to fetch multiple records at once (Fetches a number or several rows)
        
        order_data = {}      # Initializing an empty dictionary for storing the fetched data.  - This will be returned as output from our function after executing SQL query on database    
                                          
        if len(rows)!=0:       # If there is at least one row in result set (i.e., rows are not null)   .    It checks whether we have fetched any data or not  - This will be used to decide the flow of our code     
            for row in rows :     # For each loop on 'rows' variable which contains all tuples returned by last executed SQL query. (Fetches a number, several records at once)   .    It is iterating over every single tuple and storing it into dictionary  - This will be used to store data fetched from database in our function    
                order_data[row[0]] = row[1]      # Accessing each element of tuples using index (Assuming that the first column contains user id, second one for Order ID and rest are other columns)   .    It is storing these values into 'order data' dictionary. 
        
        conn.close()     # Closes database connection after fetching all records from DB - This will ensure a clean up of resources used by SQLite in the end (closes our previously opened db session).     
                                          
    except Exception as e:   # Catch block for handling any exception that might occur during execution.  . It is catching and printing out error message if there's an issue with database connection or querying    
        print("Error occurred while fetching data from the Database",e)     
        
                                          
    return order_data   # Finally, it returns 'order Data', which contains user id as key (User ID), and Order Id is value.  - This will be returned by our function after executing SQL query on database